void app_nav_init(void)
{
    memset(screens, 0, sizeof(screens));
    current = SCREEN_MAIN_MENU;
    create_screen(SCREEN_MAIN_MENU);
    lv_scr_load(screens[SCREEN_MAIN_MENU]);
    ESP_LOGI(TAG, "Navegacion inicializada");
}

app_screen_t app_nav_current(void)
{
    return current;
}

void app_nav_goto(app_screen_t screen)
{
    if (lvgl_port_lock(50)) {
        nav_switch(screen);
        lvgl_port_unlock();
    }
}

void app_nav_set_wifi(bool connected)
{
    main_menu_set_wifi(connected);
}

void app_nav_set_ha(bool online)
{
    main_menu_set_ha(online);
}

void app_nav_set_datetime(const char *date, const char *time)
{
    main_menu_set_datetime(date, time);
}

void app_nav_spotify_set_track(const char *title, const char *artist)
{
    if (lvgl_port_lock(50)) {
        spotify_set_track(title, artist);
        lvgl_port_unlock();
    }
}

void app_nav_spotify_set_progress(int32_t current_s, int32_t total_s)
{
    if (lvgl_port_lock(50)) {
        spotify_set_progress(current_s, total_s);
        lvgl_port_unlock();
    }
}

void app_nav_spotify_set_playing(bool playing)
{
    if (lvgl_port_lock(50)) {
        spotify_set_playing(playing);
        lvgl_port_unlock();
    }
}
